{
  "grammar": [
    {
      "pattern": "如果 + condition + 的話，就 + result",
      "structure": ["如果", "condition", "的話", "就", "result"],
      "explanation_en": "Use this structure to express a conditional relationship: 'if condition, then result.' The 的話 softens the condition and is optional but common in spoken Taiwanese Mandarin.",
      "title": "Conditional Sentences with 如果...的話",
      "meaning": "If (condition), then (result).",
      "when_to_use": [
        "When making hypothetical statements or plans",
        "When discussing possible scenarios in conversation"
      ],
      "when_not_to_use": [
        "Do not use for factual or habitual situations (use 的時候 instead)",
        "Avoid using when the result is certain or already happened"
      ],
      "pragmatic_notes": "In Taiwan, 如果...的話 is very common in daily speech, often shortened to just ...的話 in casual contexts. It's polite and natural for suggesting or negotiating.",
      "word_order_notes": "The condition clause comes first, followed by the result clause. 的話 attaches to the end of the condition.",
      "english_contrast": "English uses 'if' at the start of the condition; Chinese uses 如果 at the start and optionally 的話 at the end.",
      "korean_contrast": "Korean uses '-(으)면' attached to the verb; Chinese uses a separate word 如果 and optional 的話.",
      "negative_examples": [
        {
          "text": "如果我去，就我買東西。",
          "error": "The subject should be placed before 就, not after. Correct: 如果我去，我就買東西。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "如果我有錢，就買車。",
          "error": "Missing subject in the result clause; should be '我就買車' or specify who buys."
        }
      ],
      "transformation_drills": [
        "Change '如果明天下雨，我就不去公園' to use 的話: '如果明天下雨的話，我就不去公園。'"
      ],
      "production_drills": [
        "Create a sentence using 如果...的話 to talk about what you will do if you have free time this weekend."
      ],
      "common_error_patterns": [
        "Forgetting to include 就 in the result clause",
        "Placing the subject after 就 instead of before"
      ],
      "repair_feedback": {
        "word_order": "Make sure the subject comes before 就, e.g., '我就去' not '就去我'.",
        "politeness": "Using 的話 makes the condition sound softer and more polite.",
        "vocabulary": "Use appropriate verbs for the condition and result, e.g., 去, 買, 吃."
      }
    },
    {
      "pattern": "Subject + 正在 + verb + (object)",
      "structure": ["Subject", "正在", "verb", "object"],
      "explanation_en": "Use 正在 to indicate an action is in progress right now. It's equivalent to the present continuous tense in English.",
      "title": "Present Continuous with 正在",
      "meaning": "Subject is currently doing (action).",
      "when_to_use": [
        "When describing an action happening at the moment of speaking",
        "When asking what someone is doing right now"
      ],
      "when_not_to_use": [
        "Do not use for habitual actions (use 常常 or 每天 instead)",
        "Avoid using with stative verbs like 是, 有, 喜歡"
      ],
      "pragmatic_notes": "In Taiwan, 正在 is common in both formal and casual speech. In very casual conversation, 在 alone is often used instead of 正在.",
      "word_order_notes": "正在 comes directly before the verb. The object, if any, follows the verb.",
      "english_contrast": "English uses 'am/is/are + verb-ing'; Chinese uses 正在 + verb without changing the verb form.",
      "korean_contrast": "Korean uses '~고 있다' attached to the verb stem; Chinese uses a separate adverb 正在 before the verb.",
      "negative_examples": [
        {
          "text": "我正在是學生。",
          "error": "正在 cannot be used with stative verbs like 是. Use 我現在是學生 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他正在看書嗎？",
          "error": "This sentence is actually correct. No error here."
        }
      ],
      "transformation_drills": [
        "Change '他看書' to present continuous: '他正在看書。'"
      ],
      "production_drills": [
        "Describe what you are doing right now using 正在."
      ],
      "common_error_patterns": [
        "Using 正在 with stative verbs",
        "Forgetting to include 正在 when describing current actions"
      ],
      "repair_feedback": {
        "word_order": "Place 正在 directly before the verb, e.g., '我正在吃飯' not '我吃飯正在'.",
        "politeness": "Using 正在 is neutral; for polite inquiries, add 請問 at the start.",
        "vocabulary": "Use action verbs like 看, 吃, 喝, 寫, 聽."
      }
    },
    {
      "pattern": "Subject + 覺得 + (that) clause",
      "structure": ["Subject", "覺得", "clause"],
      "explanation_en": "Use 覺得 to express an opinion, feeling, or belief about something. It is similar to 'think' or 'feel' in English.",
      "title": "Expressing Opinions with 覺得",
      "meaning": "Subject thinks/feels that (clause).",
      "when_to_use": [
        "When sharing personal opinions or feelings",
        "When asking for someone's opinion"
      ],
      "when_not_to_use": [
        "Do not use for factual statements (use 是 or 知道 instead)",
        "Avoid using when you are certain about a fact"
      ],
      "pragmatic_notes": "In Taiwan, 覺得 is very common in daily conversation. It is softer than 認為 and is preferred for subjective feelings.",
      "word_order_notes": "覺得 is followed by a full clause (subject + verb + object). The clause can be a complete sentence.",
      "english_contrast": "English uses 'think' or 'feel' followed by 'that' (optional); Chinese uses 覺得 directly before the clause without a conjunction.",
      "korean_contrast": "Korean uses '~다고 생각하다' or '~는 것 같다'; Chinese uses 覺得 + clause directly.",
      "negative_examples": [
        {
          "text": "我覺得他是老師。",
          "error": "This is correct if you are expressing an opinion. If it's a fact, use 知道 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我覺得今天天氣很好。",
          "error": "This sentence is correct. No error here."
        }
      ],
      "transformation_drills": [
        "Change '我認為這本書很好' to use 覺得: '我覺得這本書很好。'"
      ],
      "production_drills": [
        "Express your opinion about the weather today using 覺得."
      ],
      "common_error_patterns": [
        "Using 覺得 for factual statements",
        "Forgetting to include a full clause after 覺得"
      ],
      "repair_feedback": {
        "word_order": "Place 覺得 before the clause, e.g., '我覺得他很聰明' not '他我覺得很聰明'.",
        "politeness": "Using 覺得 is polite; for stronger opinions, use 認為 in formal contexts.",
        "vocabulary": "Use adjectives like 好, 漂亮, 貴, 便宜, or verbs like 是, 有."
      }
    }
  ]
}
